{"content": "import SpriteKit

final class SnakeCreature: Creature {
    let node: SKNode
    let birthTime: TimeInterval
    private var bodyNode: SKShapeNode?
    private var headNode: SKShapeNode?

    init(points: [CGPoint], birthTime: TimeInterval) {
        self.birthTime = birthTime
        self.node = SKNode()
        buildSnake(from: points)
    }

    private func buildSnake(from points: [CGPoint]) {
        guard points.count >= 2 else { return }

        // 蛇身：连续粗线条，和画的时候一样
        let bodyPath = CGMutablePath()
        bodyPath.move(to: points[0])
        for i in 1..<points.count {
            bodyPath.addLine(to: points[i])
        }

        let body = SKShapeNode(path: bodyPath)
        body.lineWidth = 18
        body.lineCap = .round
        body.lineJoin = .round
        body.strokeColor = SKColor(hue: 0.55, saturation: 0.7, brightness: 0.9, alpha: 1.0)
        body.glowWidth = 4
        node.addChild(body)
        bodyNode = body

        // 蛇头：略大的圆，有物理体
        let head = SKShapeNode(circleOfRadius: 12)
        head.fillColor = SKColor.white
        head.strokeColor = body.strokeColor
        head.lineWidth = 2
        head.glowWidth = 3
        head.position = points[0]
        head.physicsBody = SKPhysicsBody(circleOfRadius: 12)
        head.physicsBody?.restitution = 0.6
        head.physicsBody?.linearDamping = 0.3
        head.physicsBody?.allowsRotation = false
        let dir = direction(from: points)
        head.physicsBody?.velocity = CGVector(dx: dir.dx * 150, dy: dir.dy * 150)
        node.addChild(head)
        headNode = head
    }

    private func direction(from points: [CGPoint]) -> (dx: CGFloat, dy: CGFloat) {
        guard points.count >= 2 else { return (1, 0) }
        let a = points[0]
        let b = points[min(points.count - 1, 3)]
        let dx = b.x - a.x
        let dy = b.y - a.y
        let len = hypot(dx, dy)
        return len > 0 ? (dx / len, dy / len) : (1, 0)
    }

    func spawn(in scene: SKScene, at position: CGPoint) {
        node.position = .zero
        scene.addChild(node)

        // 身体缓慢扭动
        let wiggle = SKAction.repeatForever(SKAction.sequence([
            SKAction.rotate(byAngle: 0.05, duration: 0.5),
            SKAction.rotate(byAngle: -0.1, duration: 0.5),
            SKAction.rotate(byAngle: 0.05, duration: 0.5),
        ]))
        node.run(wiggle)

        // 头和身体渐隐
        let wait = SKAction.wait(forDuration: 25)
        let fade = SKAction.fadeOut(withDuration: 5)
        let remove = SKAction.removeFromParent()
        node.run(SKAction.sequence([wait, fade, remove]))
    }
}
