{"content": "import SpriteKit

final class DrawingEngine {
    private var currentPath: [CGPoint] = []
    private var segmentNodes: [SKShapeNode] = []

    var isDrawing: Bool { !currentPath.isEmpty }
    var pathCount: Int { currentPath.count }

    func startPath(at point: CGPoint, in scene: SKScene) {
        currentPath = [point]
    }

    func addPoint(_ point: CGPoint, in scene: SKScene) {
        let prev = currentPath.last!
        currentPath.append(point)

        let segPath = CGMutablePath()
        segPath.move(to: prev)
        segPath.addLine(to: point)

        let seg = SKShapeNode(path: segPath)
        seg.lineWidth = 20
        seg.lineCap = .round
        seg.lineJoin = .round
        seg.strokeColor = rainbowColor(for: currentPath.count - 1, total: max(currentPath.count, 1))
        seg.glowWidth = 2
        scene.addChild(seg)
        segmentNodes.append(seg)
    }

    func finishPath() {
        // 线条留在画布上，不清除
        segmentNodes.removeAll()
        currentPath = []
    }

    func cancelPath() {
        for node in segmentNodes {
            node.removeFromParent()
        }
        segmentNodes.removeAll()
        currentPath = []
    }

    private func rainbowColor(for index: Int, total: Int) -> SKColor {
        let hue = CGFloat(index % 60) / 60.0 * 0.85
        return SKColor(hue: hue, saturation: 0.9, brightness: 1.0, alpha: 1.0)
    }
}
