import UIKit

final class CanvasScene: SKScene {
    private let engine = DrawingEngine()

    private var activeTouch: UITouch?
    private var touchStartPoint: CGPoint = .zero
    private var touchStartTime: TimeInterval = 0
    private var longPressFired = false

    private var startTime: TimeInterval = 0
    private var lastTouchTime: TimeInterval = 0
    private var isIdle = false
    private var threeFingerStartTime: TimeInterval?
    private var stickerBarVisible = false

    var onStickerBarToggle: ((Bool) -> Void)?
    var onSettingsRequest: (() -> Void)?

    override func didMove(to view: SKView) {
        backgroundColor = SKColor(red: 0.05, green: 0.05, blue: 0.15, alpha: 1.0)

        isUserInteractionEnabled = true
        startTime = CACurrentMediaTime()
        lastTouchTime = 0

        if ProcessInfo.processInfo.isLowPowerModeEnabled {
            physicsWorld.speed = 0.75
        }
    }

    // MARK: - Touches

    override func touchesBegan(_ touches: Set<UITouch>, with event: UIEvent?) {
        // 三指 → 设置
        if touches.count >= 3 {
            threeFingerStartTime = CACurrentMediaTime()
            return
        }

        guard activeTouch == nil, let touch = touches.first else { return }
        activeTouch = touch
        touchStartPoint = touch.location(in: self)
        touchStartTime = CACurrentMediaTime()
        longPressFired = false

        engine.startPath(at: touchStartPoint, in: self)

        if isIdle {
            isIdle = false
            removeAllActions()
            alpha = 1.0
        }
        lastTouchTime = CACurrentMediaTime() - startTime
    }

    override func touchesMoved(_ touches: Set<UITouch>, with event: UIEvent?) {
        guard let touch = activeTouch, touches.contains(touch), engine.isDrawing else { return }
        let current = touch.location(in: self)

        // 移动超过阈值 → 取消长按，正常画画
        if !longPressFired {
            let dist = hypot(current.x - touchStartPoint.x, current.y - touchStartPoint.y)
            if dist > 12 {
                longPressFired = true // 阻止长按
            }
        }

        engine.addPoint(current, in: self)
    }

    override func touchesEnded(_ touches: Set<UITouch>, with event: UIEvent?) {
        threeFingerStartTime = nil

        guard let touch = activeTouch, touches.contains(touch) else { return }
        activeTouch = nil

        if longPressFired {
            // 长按已触发贴纸栏，丢弃这条线
            engine.cancelPath()
        } else {
            engine.finishPath()
        }
    }

    override func touchesCancelled(_ touches: Set<UITouch>, with event: UIEvent?) {
        activeTouch = nil
        threeFingerStartTime = nil
        engine.cancelPath()
    }

    // MARK: - Update

    override func update(_ currentTime: TimeInterval) {
        let now = CACurrentMediaTime() - startTime

        // 三指长按 → 设置
        if let start = threeFingerStartTime, now - start > 3.0 {
            threeFingerStartTime = nil
            onSettingsRequest?()
        }

        // 单指长按 0.8 秒且未移动 → 贴纸栏
        if !longPressFired,
           engine.isDrawing,
           engine.pathCount <= 2,
           CACurrentMediaTime() - touchStartTime > 0.8,
           !stickerBarVisible {
            longPressFired = true
            stickerBarVisible = true
            onStickerBarToggle?(true)
        }

        // 30 秒无触摸 → 变暗
        if now - lastTouchTime > 30 && !isIdle {
            isIdle = true
            run(SKAction.fadeAlpha(to: 0.3, duration: 2))
        }
    }

    // MARK: - Sticker

    func placeSticker(imageName: String) {
        let center = CGPoint(
            x: size.width / 2 + CGFloat.random(in: -100...100),
            y: size.height / 2 + CGFloat.random(in: -100...100)
        )
        let sprite = SKSpriteNode(imageNamed: imageName)
        sprite.position = center
        sprite.setScale(0.4)
        sprite.physicsBody = SKPhysicsBody(texture: sprite.texture!, size: sprite.size)
        sprite.physicsBody?.affectedByGravity = true
        sprite.physicsBody?.restitution = 0.5
        sprite.physicsBody?.linearDamping = 0.3
        sprite.physicsBody?.allowsRotation = true
        sprite.physicsBody?.mass = 0.3
        addChild(sprite)

        let bounce = SKAction.sequence([
            SKAction.moveBy(x: 0, y: 20, duration: 0.2),
            SKAction.moveBy(x: 0, y: -20, duration: 0.2),
        ])
        sprite.run(SKAction.sequence([bounce, bounce]))

        let wait = SKAction.wait(forDuration: 35)
        let fade = SKAction.fadeOut(withDuration: 5)
        let remove = SKAction.removeFromParent()
        sprite.run(SKAction.sequence([wait, fade, remove]))

        stickerBarVisible = false
    }
}
